import { type NextRequest, NextResponse } from "next/server"

// Mock database - in production, use actual database
const audits: any[] = []

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const { audit_name, location, devices } = body

    // Create audit entry
    const audit = {
      audit_id: audits.length + 1,
      audit_name,
      location,
      audit_date: new Date().toISOString(),
      devices: devices.map((d: any) => ({
        ...d,
        daily_kwh_total: (d.power_rating_watts * d.quantity * d.hours_per_day) / 1000,
      })),
    }

    audits.push(audit)

    return NextResponse.json({ success: true, audit_id: audit.audit_id })
  } catch (error) {
    return NextResponse.json({ error: "Failed to save audit" }, { status: 500 })
  }
}
